function getSeed(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) { hash = str.charCodeAt(i) + ((hash << 5) - hash); }
  return hash;
}
function shuffleArraySeeded(array, seed) {
  let shuffled = [...array]; let currentSeed = seed;
  for (let i = shuffled.length - 1; i > 0; i--) {
      let randomVal = Math.sin(currentSeed++) * 10000;
      randomVal = randomVal - Math.floor(randomVal);
      const j = Math.floor(randomVal * (i + 1));
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  } return shuffled;
}

function getSearchLink(vendor, productName) {
  const query = encodeURIComponent(productName);
  switch(vendor) {
    case "Amazon": return `https://www.amazon.com/s?k=${query}`;
    case "Olive Young": return `https://global.oliveyoung.com/display/search?query=${query}`;
    case "Sephora": return `https://www.sephora.com/search?keyword=${query}`;
    case "Soko Glam": return `https://sokoglam.com/search?q=${query}`;
    default: return `https://www.google.com/search?q=${query}`;
  }
}

